ES6 Module Exports

1. Default Exports
With Default Exports, we can import modules with any name.

1.1 Exporting a variable while defining
We cannot export boolean, number, string, null, undefined, objects, and arrays while defining.

Example:

JAVASCRIPT
123
//sample.mjsexport default let value = 5;
JAVASCRIPT
1234
//index.mjsimport value from "./sample.mjs";console.log(value);
Output

123456
root@123# node index.mjs(node:31964) ExperimentalWarning: The ESM module loader is experimental.file:///index.mjs:1export default let value = 5;               ^^^SyntaxError: Unexpected strict mode reserved word
1.2 Exporting a variable after defining
We can export boolean, number, string, null, undefined, objects, and arrays after defining.

Example:

JAVASCRIPT
1234
//sample.mjslet a = 5;export default a;
JAVASCRIPT
1234
//index.mjsimport a from "./sample.mjs";console.log(a);
Output

123
root@123# node index.mjs(node:32665) ExperimentalWarning: The ESM module loader is experimental.5
1.3 Exporting a value or an expression
We can export a value or an expression directly.

Example:

JAVASCRIPT
123
//sample.mjsexport default 5 * 3;
JAVASCRIPT
12345
//index.mjsimport result from "./sample.mjs";console.log(result);
Output

123
root@123# node index.mjs(node:4071) ExperimentalWarning: The ESM module loader is experimental.15
1.4 Exporting a function while defining
We can export a function while defining.

Example:

JAVASCRIPT
12345
//sample.mjsexport default function (num1, num2) {  return num1 + num2;}
JAVASCRIPT
12345
//index.mjsimport sum from "./sample.mjs";console.log(sum(2, 6));
Output

123
root@123# node index.mjs(node:4278) ExperimentalWarning: The ESM module loader is experimental.8
1.5 Exporting a function after defining
We can export a function after defining.

Example:

JAVASCRIPT
123456
//sample.mjsfunction sum(num1, num2) {  return num1 + num2;}export default sum;
JAVASCRIPT
12345
//index.mjsimport sum from "./sample.mjs";console.log(sum(2, 6));
Output

123
root@123# node index.mjs(node:4462) ExperimentalWarning: The ESM module loader is experimental.8
1.6 Exporting a class while defining
We can export a class while defining.

Example:

JAVASCRIPT
12345678
//sample.mjsexport default class StudentDetails {  constructor(name, age) {    this.name = name;    this.age = age;  }}
JAVASCRIPT
1234567
//index.mjsimport StudentDetails from "./sample.mjs";const newStudentDetails = new StudentDetails("Ram", 15);console.log(newStudentDetails);console.log(newStudentDetails.name);
Output

1234
root@123# node index.mjs(node:1035) ExperimentalWarning: The ESM module loader is experimental.StudentDetails {name: "Ram", age: 15}Ram
1.7 Exporting a class after defining
We can export a class after defining.

Example:

JAVASCRIPT
123456789
//sample.mjsclass StudentDetails {  constructor(name, age) {    this.name = name;    this.age = age;  }}export default StudentDetails;
JAVASCRIPT
1234567
//index.mjsimport StudentDetails from "./sample.mjs";const newStudentDetails = new StudentDetails("Ram", 15);console.log(newStudentDetails);console.log(newStudentDetails.name);
Output

1234
root@123# node index.mjs(node:1575) ExperimentalWarning: The ESM module loader is experimental.StudentDetails {name: "Ram", age: 15}Ram
2. Named Exports
2.1 Exporting multiple variables while defining
We can export boolean, number, string, null, undefined, objects, and arrays while defining.

Example:

JAVASCRIPT
1234
//sample.mjsexport let value = 5;export let studentName = "Rahul";
JAVASCRIPT
1234567
//index.mjsimport { value, studentName } from "./sample.mjs";console.log(value);console.log(studentName);
Output

1234
root@123# node index.mjs(node:1770) ExperimentalWarning: The ESM module loader is experimental.5Rahul
2.2 Exporting multiple variables after defining
We can export multiple variables after defining in an Object format.

Example:

JAVASCRIPT
123456
//sample.mjslet value = 5;const studentName = "Rahul";export { value, studentName };
JAVASCRIPT
123456
//index.mjsimport { value, studentName } from "./sample.mjs";console.log(value);console.log(studentName);
Output

1234
root@123# node index.mjs(node:2437) ExperimentalWarning: The ESM module loader is experimental.5Rahul
2.3 Exporting multiple functions while defining
We can export multiple functions while defining.

Example:

JAVASCRIPT
123456789
//sample.mjsexport function sum(num1, num2) {  return num1 + num2;}export function sub(num1, num2) {  return num1 - num2;}
JAVASCRIPT
1234567
//index.mjsimport { sum, sub } from "./sample.mjs";console.log(sum(4, 2));console.log(sub(4, 2));
Output

1234
root@123# node index.mjs(node:2954) ExperimentalWarning: The ESM module loader is experimental.62
2.4 Exporting multiple functions after defining
We can export multiple functions after defining.

Example:

JAVASCRIPT
1234567891011
//sample.mjsfunction sum(num1, num2) {  return num1 + num2;}function sub(num1, num2) {  return num1 - num2;}export { sum, sub }; 
Expand
JAVASCRIPT
1234567
//index.mjsimport { sum, sub } from "./sample.mjs";console.log(sum(4, 2));console.log(sub(4, 2));
Output

1234
root@123# node index.mjs(node:3276) ExperimentalWarning: The ESM module loader is experimental.62
2.5 Exporting multiple classes while defining
We can export multiple classes while defining.

Example:

JAVASCRIPT
1234567891011
//sample.mjsexport class StudentDetails {  constructor(name, age) {    this.name = name;    this.age = age;  }}export class CarDetails {  constructor(name, speed) { 
Expand
JAVASCRIPT
1234567891011
//index.mjsimport { StudentDetails, CarDetails } from "./sample.mjs";const newStudentDetails = new StudentDetails("Ram", 15);console.log(newStudentDetails);console.log(newStudentDetails.name);const newCarDetails = new CarDetails("Alto", "60kmph");console.log(newCarDetails);console.log(newCarDetails.name); 
Expand
Output

123456
root@123# node index.mjs(node:3517) ExperimentalWarning: The ESM module loader is experimental.StudentDetails { name: 'Ram', age: 15 }RamCarDetails { name: 'Alto', speed: '60kmph' }Alto
2.6 Exporting multiple classes after defining
We can export multiple classes after defining.

Example:

JAVASCRIPT
1234567891011
//sample.mjsclass StudentDetails {  constructor(name, age) {    this.name = name;    this.age = age;  }}class CarDetails {  constructor(name, speed) { 
Expand
JAVASCRIPT
1234567891011
//index.mjsimport { StudentDetails, CarDetails } from "./sample.mjs";const newStudentDetails = new StudentDetails("Ram", 15);console.log(newStudentDetails);console.log(newStudentDetails.name);const newCarDetails = new CarDetails("Alto", "60kmph");console.log(newCarDetails);console.log(newCarDetails.name); 
Expand
Output

123456
root@123# node index.mjs(node:3841) ExperimentalWarning: The ESM module loader is experimental.StudentDetails {name: "Ram", age: 15}RamCarDetails {name: "Alto", speed: "60kmph"}Alto
